import { Button, Dialog, DialogContent, DialogTitle, makeStyles } from '@material-ui/core'
import React from 'react'
import { useState } from 'react'

const useStyle = makeStyles(theme => {
    return {
        root: {
            zIndex: 2
        }
    }
})




export default function Quiz() {
    const classes = useStyle()
    const [quiz, setQuiz] = useState(false);

    const openQuiz = () => {
        setQuiz(true)
    };
    const closeQuiz = () => {
        setQuiz(false)
    };

  return (
    <div className={classes.root}>
    <Button variant='contained' color='secondary' onClick={openQuiz}>
        Open Dialog
    </Button>
        <Dialog className={classes.dialog} open={quiz} onClose={closeQuiz} fullScreen>
            <DialogTitle>Quiz 1</DialogTitle>
            <DialogContent>
                Hello Worldaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa
            </DialogContent>
        </Dialog>
    </div>
  )
}
